#!/usr/bin/env node
import fs from 'node:fs/promises'
import YAML from 'yaml'

const YAML_OPTIONS = { indent: 2, lineWidth: 0 }

function transform(node) {
  if (Array.isArray(node)) {
    let changed = false
    for (const item of node) changed = transform(item) || changed
    return changed
  }
  if (node == null || typeof node !== 'object') return false
  let changed = false
  // ... your mutation logic here ...
  for (const value of Object.values(node)) changed = transform(value) || changed
  return changed
}

async function main() {
  const [filePath] = process.argv.slice(2)
  const raw = await fs.readFile(filePath, 'utf8')
  const doc = YAML.parse(raw)
  const changed = transform(doc)
  if (changed) {
    const out = YAML.stringify(doc, YAML_OPTIONS)
    await fs.writeFile(filePath, out.endsWith('\n') ? out : out + '\n', 'utf8')
  }
}
await main()
